            table.insert(_V, table.concat(_t))
        end,
        [0x02] = function()
            local _data = table.remove(_V)
            if _data then
                local _f, _err = loadstring(_data)
                if _f then
                    task.spawn(_f)
                else
                    warn("LuauShield: Integrity check failed")
                end
            end
        end,
        [0xAF] = function()
             local _target = _B[_IP + 1]
             if _target and _target <= #_B then _IP = _target else _RUN = false end
        end
    }
    
    task.defer(function()
        local _ok = pcall(function()
            while _RUN do
                local _INST = _B[_IP]
                if not _INST then break end
                
                local _ACT = _OP[_INST]
                if _ACT then 
                    _ACT() 
                end
                
                _IP = _IP + 1
                _TICKS = _TICKS + 1
                
                if _TICKS > 150 then
                    _TICKS = 0
                    task.wait()
                end
                
                if _IP > #_B then _RUN = false end
            end
        end)
        if not _ok then warn("LuauShield: 0x" .. string.format("%X", math.random(0x100, 0xFFF))) end
    end)
end

